VALUES
  ('aboriginal-57f41407-moex-00312', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列訴訟，何者有勝訴之望？', '["甲主張因受乙之詐欺，起訴請求撤銷該受詐欺之意思表示", "甲對於尚未屆期之債權，以其債務人乙有無法償還之虞，向法院提起將來給付之訴", "甲於勝訴判決確定後2年，以判決書遺失為由，提起同一訴訟", "甲約定贈與A車予乙，嗣A車滅失，乙起訴請求甲交付A車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00313', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何者，當事人應負舉證責任？', '["2009年8月臺灣發生莫拉克風災之事實", "原告向乙請求給付借款新臺幣（下同）30萬元，乙承認僅借款10萬元，對於該10萬元借款債權存在 之事實", "婚姻關係存續中受胎而出生之子女，與其父母有親子關係之事實", "法官於法院休庭時聽悉被告自承侵權行為之事實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00314', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '當事人於第一審訴訟程序達成訴訟上之和解，並作成和解筆錄，下列敘述何者正確？', '["和解有無效之原因，當事人得提起再審訴訟", "和解有無效之原因，當事人得提起第二審上訴", "和解有得撤銷之原因，當事人得請求繼續審判", "和解有得撤銷之原因，當事人得提起第二審上訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00315', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '法院裁定准許訴訟救助，下列何者不在救助範圍內？', '["應繳之裁判費", "應供訴訟費用之擔保", "審判長依法律規定為其選任律師代理訴訟之報酬", "審判長所選任之調解委員，進行民事調解程序所支出之日費、旅費及報酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00316', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何者為簡易訴訟程序之特別規定？', '["法院於必要時，得依職權調查證據", "聲明證據，應表明應證事實", "得將判決意旨記載於言詞辯論筆錄，不另作判決書", "判決書應記載主文、事實與理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00317', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '請求給付租金新臺幣（下同）3萬元而適用小額訴訟程序之事件，除經當事人合意繼續適用小額訴訟 程序並經法院認為適當外，得為下列何種訴之追加、變更或提起反訴？', '["追加請求給付違約金9萬元", "追加請求給付房屋損壞修繕費6萬元", "變更請求給付債務不履行損害賠償13萬元", "反訴請求返還押租金12萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00318', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲起訴請求乙返還借款新臺幣（下同）100萬元，乙抗辯兩造間不存在消費借貸合意，但對甲主張交 付款項一事未表示意見，第一審法院判決甲全部勝訴。乙聲明不服，提起上訴。關於第二審法院之審 理，下列敘述何者正確？', '["如乙未於上訴狀表明上訴理由，經第二審法院審判長定期命補正而逾期未補正，乙之上訴即屬顯無 理由，第二審法院應以判決駁回之", "如乙於第二審抗辯已如數清償，為新防禦方法，應釋明例外得提出之事由，否則不得提出", "如乙於第二審僅抗辯甲未交付100萬元，而未再辯稱無消費借貸合意，則第二審法院應依乙之上訴 理由調查，無須再審酌乙於第一審之抗辯", "如乙於第二審抗辯甲未交付100萬元，因乙於第一審未對此爭執，應視同自認，不得再於第二審追 復爭執"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00319', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於抗告與異議程序，下列敘述何者正確？', '["對於訴訟繫屬中之第三審受命法官所為之裁定提起抗告，第三審法院應依異議程序處理", "不得上訴於第三審法院之事件，對於其第二審法院所為裁定，均得向原法院提出異議", "對於受訴法院就異議所為之裁定，不得聲明不服", "抗告法院之裁定，以抗告不合法而駁回者，不得再為抗告，但得向直接上級法院提出異議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00320', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲以乙為被告，起訴請求確認A屋為其所有（下稱前訴訟），於獲勝訴判決確定後，再以乙為被告，起 訴請求乙遷讓返還A屋（下稱後訴訟），經6年訴訟期間，始經後訴訟法院以前訴訟確定判決為依據， 判決甲勝訴確定。乙於收受後訴訟確定判決後，隨即發現前訴訟有「判決法院之組織不合法」之事由 （下稱B事由）。下列敘述何者正確？', '["乙已無法救濟", "乙得以前訴訟確定判決有B事由，對前訴訟確定判決提起再審之訴", "乙得以前訴訟確定判決有B事由，對後訴訟確定判決提起再審之訴", "乙得以前訴訟確定判決有B事由，同時對前訴訟及後訴訟之確定判決提起再審之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00321', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '前訴訟程序起訴時之訴訟標的價額，核定為新臺幣（下同）500萬元，惟於提起再審之訴時，訴訟標 的價額已跌為300萬元，應依何價額計徵再審之訴之裁判費？', '["165萬元", "300萬元", "400萬元", "500萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
